// Ingesta WhatsApp Cloud API: correlaciona mensaje de UBICACIÓN + IMAGEN por número de teléfono.
// Variables de entorno requeridas en n8n:
//   WHATSAPP_TOKEN            -> token permanente de la app de Meta (WhatsApp Business)
//   WHATSAPP_PHONE_NUMBER_ID  -> id del número emisor (para responder al usuario)
const token = $env.WHATSAPP_TOKEN || 'PEGA_TU_TOKEN_AQUI';
const phoneId = $env.WHATSAPP_PHONE_NUMBER_ID || '';
const sd = $getWorkflowStaticData('global');
sd.photos = sd.photos || [];
sd.pending = sd.pending || {};

const body = $json.body || $json;
const entry = (body.entry && body.entry[0]) || {};
const change = (entry.changes && entry.changes[0]) || {};
const value = change.value || {};
const msg = (value.messages && value.messages[0]) || null;
if (!msg) return [{ json: { handled: false, reason: 'sin mensaje (status u otro evento)' } }];
const from = msg.from; // teléfono del remitente

async function reply(text) {
  if (!phoneId || !from) return;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v20.0/${phoneId}/messages`,
      headers: { Authorization: `Bearer ${token}` },
      body: { messaging_product: 'whatsapp', to: from, type: 'text', text: { body: text } },
      json: true,
    });
  } catch (e) {}
}

let out = { handled: false };

if (msg.type === 'location' && msg.location) {
  sd.pending[from] = { lat: msg.location.latitude, lon: msg.location.longitude };
  await reply.call(this, '📍 Ubicación recibida. Ahora envíame la foto y la ubicaré en el visor LifeCity.');
  out = { handled: 'location', lat: msg.location.latitude, lon: msg.location.longitude };
}
else if (msg.type === 'image' && msg.image) {
  // 1) URL temporal del medio
  const media = await this.helpers.httpRequest({
    url: `https://graph.facebook.com/v20.0/${msg.image.id}`,
    headers: { Authorization: `Bearer ${token}` }, json: true,
  });
  // 2) Descarga el binario (la URL de Meta exige el token) y guárdalo como data URI
  const bin = await this.helpers.httpRequest({
    url: media.url, headers: { Authorization: `Bearer ${token}` },
    encoding: 'arraybuffer', returnFullResponse: true,
  });
  const b64 = Buffer.from(bin.body).toString('base64');
  const mime = media.mime_type || 'image/jpeg';
  const dataUri = `data:${mime};base64,${b64}`;
  const loc = sd.pending[from];
  if (!loc) {
    await reply.call(this, '⚠️ No tengo tu ubicación. Envía primero 📎 → Ubicación y luego la foto.');
    out = { handled: 'foto_sin_ubicacion' };
  } else {
    const rec = {
      id: String(msg.id),
      url: dataUri,
      caption: (msg.image.caption || ''),
      date: new Date((+msg.timestamp || 0) * 1000).toISOString(),
      lat: loc.lat, lon: loc.lon,
      source: 'whatsapp'
    };
    sd.photos.push(rec);
    if (sd.photos.length > 200) sd.photos.shift(); // los data URI pesan: límite corto
    delete sd.pending[from];
    await reply.call(this, `✅ Foto ubicada en ${loc.lat.toFixed(5)}, ${loc.lon.toFixed(5)}. Total: ${sd.photos.length}.`);
    out = { handled: 'foto', id: rec.id, lat: rec.lat, lon: rec.lon };
  }
}
return [{ json: out }];

// Devuelve el arreglo acumulado de fotos geolocalizadas (formato del visor LifeCity).
const sd = $getWorkflowStaticData('global');
return [{ json: { photos: sd.photos || [] } }];
